package main

import "fmt"

func main() {
	ages := map[string]int{
		"Ali":  25,
		"Veli": 30,
		"Ayse": 28,
	}

	fmt.Println("Tum kayitlar:")
	for name, age := range ages {
		fmt.Println(name, "->", age, "yasinda")
	}

	// Anahtar kontrolu
	if age, ok := ages["Ali"]; ok {
		fmt.Println("\nAli'nin yasi:", age)
	}

	// Guncelleme
	ages["Ali"] = 26
	fmt.Println("Ali'nin yeni yasi:", ages["Ali"])

	// Yeni eleman ekleme
	ages["Can"] = 22
	fmt.Println("\nCan eklendi, kayit sayisi:", len(ages))

	// Silme
	delete(ages, "Veli")
	fmt.Println("\nVeli silindikten sonra kayit sayisi:", len(ages))

	// Olmayan anahtar kontrolu
	if _, ok := ages["Zeynep"]; !ok {
		fmt.Println("\nZeynep map'te bulunamadi.")
	}
}
